import type { Placement } from '@floating-ui/react';
import type { ReactNode } from 'react';
export interface PopoverHelperProps {
    /**
     * Состояние отображения: отображено / скрыто.
     */
    open?: boolean;
    /**
     * Отключает отображение при событии наведения.
     */
    disableHover?: boolean;
    /**
     * Режим отображения: по наведению, по клику или оба.
     * @default 'hover'
     */
    triggerMode?: 'hover' | 'click' | 'both';
    /**
     * Режим закрытия поповера
     * - 'auto': закрывается при клике вне поповера или по триггеру (по умолчанию)
     * - 'manual': закрывается только программно через open={false}
     * - 'content-click': закрывается при клике по содержимому поповера
     * - 'outside-click': закрывается только при клике вне поповера
     * @default 'auto'
     */
    closeMode?: 'auto' | 'manual' | 'content-click' | 'outside-click';
    /**
     * Автоматически закрывать поповер при скролле страницы
     * @default false
     */
    closeOnScroll?: boolean;
    /**
     * Callback, вызываемый при скролле страницы (когда поповер открыт)
     * Если возвращает true, поповер будет закрыт
     */
    onScroll?: (event: Event) => boolean | void;
    /**
     * Заголовок.
     */
    title?: ReactNode;
    /**
     * Основное содержимое.
     */
    body: string | ReactNode;
    /**
     * Пользовательский класс
     */
    className?: string;
    /**
     * Пользовательский класс для обертки над компонентом Helper.
     */
    popoverRootClassName?: string;
    /**
     * Пользовательский класс для добавления класса порталу.
     */
    portalClassName?: string;
    /**
     * Прикреплять портал к children вместо root
     * @default false
     */
    attachToChildren?: boolean;
    /**
     * Положение поповера относительно якорного элемента
     * Совместимо с @floating-ui/react Placement
     * @default 'bottom'
     */
    placement?: Placement;
    /**
     * Дочерние элементы.
     */
    children?: React.JSX.Element;
}
